-- Real bank underwriting guideline data, transcribed from the user's Google
-- Sheet "BANK GUIDELINE" (18 banks). Replaces the 3 placeholder demo banks'
-- calc_params with real data (same IDs, so existing demo cases keep working)
-- and adds the remaining 15 banks. calc_params.guideline holds the full
-- verbatim underwriting criteria (DSR, NDI, bonus/ASB/variable-income
-- formulas, self-employed rules, tenure, credit bureau, etc.) for officer
-- reference; calc_params.dsr_tiers / income_rules are a best-effort
-- simplification of that text so the existing deterministic calculation
-- engine can still run — see calc_params.notes on each bank.


update banks set name = 'RHB Bank', calc_params = '{"bank_code": "RHB", "dsr_tiers": [{"max": 3000, "dsr": 0.6}, {"max": 5000, "dsr": 0.7}, {"max": 8000, "dsr": 0.8}, {"max": 13000, "dsr": 0.85}, {"max": null, "dsr": 0.9}], "income_rules": {"employed": {"basic": 1.0, "allowance": 0.5, "commission": 0.5, "rental": 0.8}, "self_employed": {"net_profit": 0.7}, "commission": {"basic": 1.0, "commission": 0.5}}, "stress_rate": 0.045, "tenure_max_years": 35, "notes": "DSR tiers use the urban/conservative rate where the source guideline splits by urban vs non-urban or property status; income_rules multipliers are simplified from variable/rental/self-employed formulas that may involve caps, shareholding %, or multi-period averaging our income entry model doesn''t capture. stress_rate is a placeholder (not in the source sheet) \u2014 update with each bank''s actual rate. See guideline for the full verbatim underwriting criteria.", "guideline": {"dsr": "GROSS INCOME BELOW 3K - 60%\nGROSS INCOME 3001~5000 - 70%\nGROSS INCOME 5001~8000 - 80%\nGROSS INCOME 8001~13000 - 85%\nGROSS INCOME > 13000 - 90%", "sjkp_100pct_financing": "Criteria:\n1. ONLY applicable to 1st home application\n2. Completed/under-con\n3. SPA from RM 30,000 - RM 1,000,000\n4. Gross Income < RM 5k, SPA not more than RM 300k, MOF @ 110%\n5. Gross income RM 5k-RM 15k, SPA from 30,000-1,000,000, MOF @ 105%\n6. Compulsory Min 2% insurance coverage\n7. ONLY proceed good scoring customer: RG1-4/1XC\n8. Require a min 5% AUM, if without AUM subject to customer profile\n9. Tenure up to 35 years OR 70 years old", "ndi": "SA 900\nJA 1350", "urban_listing": "N/A", "bonus": "1 YEAR 50% / 12\n2 YEAR ~ (YEAR1+YEAR2)/2/12", "asb": "(CURRENT VALUE X 5.75%) / 12", "variable_income": "AVERAGE OF 6 MONTHS X 50% (IF 2 MONTHS VARIANCE MORE THAN 50%, NOT INTAKE OF VARIABLE INCOME)", "rental_income": "NEW WITH STAMPING - 50%\n3 MONTHS WITH STAMPING - 80%\n6 MONTHS WITH STAMPING - 100%", "sgd_income": "CONVERT RATE FOLLOW WEBSITE; GROSS INCOME = CONVERTED MYR X 85%; NETT INCOME = GROSS INCOME X 75%", "cbs_grade": "GRADE MUST SHOW AA, IF NO GRADE MORE GOOD", "self_employed_by_tax": "KEY IN NIC. VARIANCE = (CURRENT YEAR TAX - PREVIOUS TAX)/PREVIOUS YEAR TAX. <10%: take 100% current year. >10%,<30%: take 90%. >30%,<50%: take 70%. >50%: take 50%.", "self_employed_by_bank_statement": "6 MONTH AVERAGE X 6% X SHAREHOLDING %", "tax_needed": "100% LOAN CAN TRY NO NEED, BUT MOSTLY NEED 2 YEARS TAX", "trade_reference": "COWAY/TELCO BELOW 5K DEPENDS ON SCORING", "credit_bureau": "CTOS", "master_title_over_10_years": "CAN", "ptptn": "DEPENDS ON SCORING", "min_age": "MIN 18 YEARS OLD SUBJECT TO PURCHASE PRICE AND WORKING MORE THAN 1 YEAR", "epf_problem": "NEED LETTER, AND MUST HAVE SOME MONTH CONTRIBUTION", "legal_fees_and_valuation_fees": "CAN FINANCE (SPA & LOAN SAME LAWYER CAN FINANCE SPA)", "no_bank_statement": "MUST HAVE ORIGINAL STATEMENT", "clean_ccris": "CAN > AGE 40, NEED SETTLEMENT LETTER & SAVING", "cc_max_usage": "EMPLOYED - 90%, SELF EMPLOYED - 80%. OVER LIMIT IF DSR NO BURST, CLEAR AND SUBMIT", "new_employment": "ONE MONTH PAYSLIP WITH PREVIOUS EMPLOYMENT DOC", "perkeso_income": "YES", "pencen_income": "YES", "dual_income": "NO", "part_time": "MUST BE RELATED FIELD. BOTH EMPLOYMENT NEED DO SITE VISIT AND GET EVL. CONSIDER AS VARIABLE INCOME TO KEY IN TO NIC.", "part_time_income_calculation": "AVERAGE OF 6 MONTH X 50%", "legal_case": "IF WITHIN 2 YEAR SUBJECT TO OFFICER APPROVAL", "max_cashout_for_refinance": null, "refinance_co_tenure": null, "housing_loan_tenure": "35 YEARS OR 70 YEARS OLD, WHICHEVER COMES FIRST", "using_perfios_system": "YES"}}'::jsonb, doc_requirements = '["3 months payslip", "6 months bank statement", "EA Form / Income Tax (BE Form)", "IC (front & back)", "EPF Statement (3 months)", "Offer Letter / SPA"]'::jsonb where id = '33333333-3333-3333-3333-333333333333';


update banks set name = 'CIMB Bank', calc_params = '{"bank_code": "CIMB", "dsr_tiers": [{"max": 2000, "dsr": 0.44}, {"max": 2500, "dsr": 0.53}, {"max": 5000, "dsr": 0.6}, {"max": 6000, "dsr": 0.85}, {"max": null, "dsr": 0.9}], "income_rules": {"employed": {"basic": 1.0, "allowance": 0.8, "commission": 0.8, "rental": 0.8}, "self_employed": {"net_profit": 0.8}, "commission": {"basic": 1.0, "commission": 0.8}}, "stress_rate": 0.045, "tenure_max_years": 35, "notes": "DSR tiers use the urban/conservative rate where the source guideline splits by urban vs non-urban or property status; income_rules multipliers are simplified from variable/rental/self-employed formulas that may involve caps, shareholding %, or multi-period averaging our income entry model doesn''t capture. stress_rate is a placeholder (not in the source sheet) \u2014 update with each bank''s actual rate. See guideline for the full verbatim underwriting criteria.", "guideline": {"dsr": "INCOME < 2K - 44%\nINCOME 2K~2.5K - 53%\nINCOME 2.5K~5K - 60%\nGROSS & NETT INCOME 5K - 80%\nNETT INCOME 5k~6k - 85%\nNETT INCOME 6k and above - 90%", "sjkp_100pct_financing": "< 2K - 44%\n2K~2.5K - 53%\n2.5K~5K - 60%\nGross and nett 5K - 80%\nNett 5k~6k - 85%\nNett 6k and above - 90%\nMax 1mil SPA", "ndi": "SA 1100\nJA 1200", "urban_listing": "N/A", "bonus": "1 YEAR BONUS / 12 X 50%\n2 YEAR BONUS AVERAGE / 12 X 100%", "asb": "DIVIDEND / 12", "variable_income": "AVERAGE OF 6 MONTHS X 80%", "rental_income": "6 MONTHS WITH STAMPING X 80%", "sgd_income": "1 SGD = 3.15 MYR X 80% = NETT", "cbs_grade": "GRADE MUST SHOW AA, IF NO GRADE MORE GOOD", "self_employed_by_tax": "JUMLAH PENDAPATAN X 80% / 12", "self_employed_by_bank_statement": "6 MONTH AVERAGE X 10% X SHAREHOLDING %", "tax_needed": "CAN TRY WITHOUT TAX", "trade_reference": "CCRIS MORE THAN 1 YEAR - NO CHECK", "credit_bureau": "BNM", "master_title_over_10_years": "NO", "ptptn": "DEPENDS ON SCORING", "min_age": "MIN 21 YEARS OLD", "epf_problem": "STRAIGHT MAGIC PAYSLIP TO FULL COMMISSION ONLY SUBMIT", "legal_fees_and_valuation_fees": "CAN FINANCE MAX 3%", "no_bank_statement": "CAN", "clean_ccris": "INCOME MUST ABOVE 8000", "cc_max_usage": "BETTER BELOW 60%", "new_employment": "ONE MONTH PAYSLIP WITH PREVIOUS EMPLOYMENT DOC", "perkeso_income": "YES", "pencen_income": "YES", "dual_income": null, "part_time": "YES", "part_time_income_calculation": "AVERAGE OF 6 MONTH X 50%", "legal_case": "IF CCRIS MORE THAN 1 YEAR, WON''T SEE CTOS, CAN FIGHT", "max_cashout_for_refinance": "CAN 200K REFI, THEN ADD 200K OD REFI, THEN DO 3RD REFINANCE AGAIN", "refinance_co_tenure": "REFINANCE CAN MAX TENURE, CASH OUT ONLY 10 YEARS", "housing_loan_tenure": "35 YEARS OR 70 YEARS OLD, WHICHEVER COMES FIRST", "using_perfios_system": "NO"}}'::jsonb, doc_requirements = '["3 months payslip", "6 months bank statement", "EA Form / Income Tax (BE Form)", "IC (front & back)", "EPF Statement (3 months)", "Offer Letter / SPA"]'::jsonb where id = '22222222-2222-2222-2222-222222222222';

update banks set name = 'Maybank', calc_params = '{"bank_code": "MBB", "dsr_tiers": [{"max": 3500, "dsr": 0.4}, {"max": null, "dsr": 0.7}], "income_rules": {"employed": {"basic": 1.0, "allowance": 0.7, "commission": 0.7, "rental": 0.8}, "self_employed": {"net_profit": 1.0}, "commission": {"basic": 1.0, "commission": 0.7}}, "stress_rate": 0.045, "tenure_max_years": 35, "notes": "DSR tiers use the urban/conservative rate where the source guideline splits by urban vs non-urban or property status; income_rules multipliers are simplified from variable/rental/self-employed formulas that may involve caps, shareholding %, or multi-period averaging our income entry model doesn''t capture. stress_rate is a placeholder (not in the source sheet) \u2014 update with each bank''s actual rate. See guideline for the full verbatim underwriting criteria.", "guideline": {"dsr": "NETT INCOME < 3.5K - 40%\nNETT INCOME > 3.5K - 70%", "sjkp_100pct_financing": "DSR 60%\nMax 500k SPA", "ndi": "KL 1300\nSRB 1000", "urban_listing": "N/A", "bonus": "2 YEAR AVERAGE X 70%", "asb": "DIVIDEND / 12", "variable_income": "AVERAGE OF 6 MONTHS X 70%", "rental_income": "6 MONTHS WITH STAMPING X 80%", "sgd_income": "1 SGD = FOLLOW WEBSITE CONVERSION RATE X 100% = NETT INCOME IN MYR", "cbs_grade": "GRADE MUST SHOW AA, IF NO GRADE MORE GOOD", "self_employed_by_tax": "TOTAL INCOME / 12", "self_employed_by_bank_statement": "6 MONTH AVERAGE X 6% X SHAREHOLDING %", "tax_needed": "2 YEARS TAX NEEDED", "trade_reference": "NO CHECK", "credit_bureau": "OWN", "master_title_over_10_years": "NO", "ptptn": "DEPENDS ON SCORING", "min_age": "MIN 21 YEARS OLD", "epf_problem": "NEED LETTER", "legal_fees_and_valuation_fees": "CAN FINANCE ANY AMOUNT", "no_bank_statement": "NO", "clean_ccris": "BELOW AGE 30", "cc_max_usage": "99% USAGE STILL CAN", "new_employment": "ONE MONTH PAYSLIP WITH PREVIOUS EMPLOYMENT DOC", "perkeso_income": "YES", "pencen_income": "YES", "dual_income": null, "part_time": "YES", "part_time_income_calculation": "AVERAGE OF 6 MONTH X 50%", "legal_case": "MOSTLY CAN''T SEE LEGAL CASE", "max_cashout_for_refinance": null, "refinance_co_tenure": null, "housing_loan_tenure": "35 YEARS OR 70 YEARS OLD, WHICHEVER COMES FIRST", "using_perfios_system": "NO"}}'::jsonb, doc_requirements = '["3 months payslip", "6 months bank statement", "EA Form / Income Tax (BE Form)", "IC (front & back)", "EPF Statement (3 months)", "Offer Letter / SPA"]'::jsonb where id = '11111111-1111-1111-1111-111111111111';













